import os, json, shlex, subprocess, textwrap, re
from typing import List, Optional, Dict, Any


def list_files(path: str = ".") -> str:
    """List files in a directory. Returns a newline-separated listing."""
    try:
        if not path:
            path = "."
        if not os.path.isdir(path):
            return f"ERROR: Not a directory: {path}"
        entries = sorted(os.listdir(path))
        lines = []
        for e in entries:
            full = os.path.join(path, e)
            suffix = "/" if os.path.isdir(full) else ""
            lines.append(e + suffix)
        return "\n".join(lines) if lines else "(empty)"
    except Exception as e:
        return f"ERROR listing files: {e}"


def file_exists(path: str) -> str:
    """Check whether a file exists. Returns 'true' or an error message."""
    try:
        if not path:
            return "ERROR: No path provided"
        return "true" if os.path.exists(path) else f"false: {path} does not exist"
    except Exception as e:
        return f"ERROR: {e}"


def run_command(command: str, timeout_seconds: int = 3600, cwd: Optional[str] = None) -> str:
    """PUBLIC: Execute a shell command safely (no shell). Accepts a full command string and returns JSON with exit_code, stdout, stderr, and command.

    This is the public replacement for any private _run usage.
    """
    try:
        if not command or not command.strip():
            return "ERROR: command is empty"
        args = shlex.split(command)
        # Basic guardrail: disallow interactive commands that could hang
        if any(a in args for a in ["-i:", "-stdin", "--stdin"]):
            pass
        proc = subprocess.run(
            args,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            timeout=timeout_seconds,
            cwd=cwd,
            check=False,
        )
        out = {
            "command": command,
            "exit_code": proc.returncode,
            "stdout": proc.stdout[-20000:],
            "stderr": proc.stderr[-20000:],
        }
        return json.dumps(out, indent=2)
    except subprocess.TimeoutExpired as e:
        return json.dumps({"command": command, "exit_code": None, "stdout": "", "stderr": f"TIMEOUT after {timeout_seconds}s: {e}"}, indent=2)
    except FileNotFoundError as e:
        return json.dumps({"command": command, "exit_code": 127, "stdout": "", "stderr": f"NOT FOUND: {e}"}, indent=2)
    except Exception as e:
        return json.dumps({"command": command, "exit_code": 1, "stdout": "", "stderr": f"ERROR: {e}"}, indent=2)


def run_ffmpeg(args: str, timeout_seconds: int = 3600, cwd: Optional[str] = None) -> str:
    """Run an arbitrary ffmpeg argument string (without needing to include the 'ffmpeg' binary). Always prepends 'ffmpeg -y'. Returns JSON."""
    try:
        if args is None:
            return "ERROR: args is None"
        cmd = f"ffmpeg -y {args}".strip()
        return run_command(cmd, timeout_seconds=timeout_seconds, cwd=cwd)
    except Exception as e:
        return f"ERROR: {e}"


def run_ffprobe(args: str, timeout_seconds: int = 3600, cwd: Optional[str] = None) -> str:
    """Run an arbitrary ffprobe argument string (without needing to include the 'ffprobe' binary). Returns JSON."""
    try:
        if args is None:
            return "ERROR: args is None"
        cmd = f"ffprobe {args}".strip()
        return run_command(cmd, timeout_seconds=timeout_seconds, cwd=cwd)
    except Exception as e:
        return f"ERROR: {e}"


def get_media_info(path: str) -> str:
    """Return full media metadata as JSON using ffprobe."""
    try:
        if not path:
            return "ERROR: path is required"
        if not os.path.exists(path):
            return f"ERROR: file not found: {path}"
        args = f"-v error -print_format json -show_format -show_streams {shlex.quote(path)}"
        return run_ffprobe(args)
    except Exception as e:
        return f"ERROR: {e}"


def get_duration(path: str) -> str:
    """Get media duration in seconds as a string."""
    try:
        if not path:
            return "ERROR: path is required"
        if not os.path.exists(path):
            return f"ERROR: file not found: {path}"
        args = f"-v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 {shlex.quote(path)}"
        result = run_ffprobe(args)
        try:
            j = json.loads(result)
            return result
        except Exception:
            # If run_ffprobe returns json wrapper, parse stdout
            try:
                wrapped = json.loads(result)
                return (wrapped.get("stdout") or "").strip() or result
            except Exception:
                return result
    except Exception as e:
        return f"ERROR: {e}"


def _quote(p: str) -> str:
    return shlex.quote(p)


def convert_video(input_path: str, output_path: str, video_codec: str = "libx264", crf: int = 23, preset: str = "medium", audio_codec: str = "aac", audio_bitrate_k: int = 128) -> str:
    """Convert a video to a new format/codec using sensible defaults."""
    try:
        if not os.path.exists(input_path):
            return f"ERROR: input not found: {input_path}"
        args = f"-i {_quote(input_path)} -c:v {video_codec} -preset {preset} -crf {crf} -c:a {audio_codec} -b:a {audio_bitrate_k}k {_quote(output_path)}"
        return run_ffmpeg(args)
    except Exception as e:
        return f"ERROR: {e}"


def convert_audio(input_path: str, output_path: str, audio_codec: str = "aac", audio_bitrate_k: int = 192, sample_rate: Optional[int] = None, channels: Optional[int] = None) -> str:
    """Convert an audio file to a new format/codec."""
    try:
        if not os.path.exists(input_path):
            return f"ERROR: input not found: {input_path}"
        extra = ""
        if sample_rate:
            extra += f" -ar {int(sample_rate)}"
        if channels:
            extra += f" -ac {int(channels)}"
        args = f"-i {_quote(input_path)} -c:a {audio_codec} -b:a {audio_bitrate_k}k{extra} {_quote(output_path)}"
        return run_ffmpeg(args)
    except Exception as e:
        return f"ERROR: {e}"


def extract_audio(input_video: str, output_audio: str, audio_codec: str = "aac", audio_bitrate_k: int = 192) -> str:
    """Extract audio from a video."""
    try:
        if not os.path.exists(input_video):
            return f"ERROR: input not found: {input_video}"
        args = f"-i {_quote(input_video)} -vn -c:a {audio_codec} -b:a {audio_bitrate_k}k {_quote(output_audio)}"
        return run_ffmpeg(args)
    except Exception as e:
        return f"ERROR: {e}"


def trim_media(input_path: str, output_path: str, start_time: str, end_time: Optional[str] = None, duration: Optional[str] = None) -> str:
    """Trim media using stream copy when possible."""
    try:
        if not os.path.exists(input_path):
            return f"ERROR: input not found: {input_path}"
        if not start_time:
            return "ERROR: start_time is required"
        if end_time and duration:
            return "ERROR: Provide either end_time or duration, not both"
        if end_time:
            # duration = end - start is harder; use -to with input seeking for simplicity
            args = f"-ss {start_time} -to {end_time} -i {_quote(input_path)} -c copy {_quote(output_path)}"
        elif duration:
            args = f"-ss {start_time} -i {_quote(input_path)} -t {duration} -c copy {_quote(output_path)}"
        else:
            return "ERROR: end_time or duration is required"
        return run_ffmpeg(args)
    except Exception as e:
        return f"ERROR: {e}"


def compress_video(input_path: str, output_path: str, crf: int = 28, preset: str = "medium", video_codec: str = "libx264", audio_bitrate_k: int = 128) -> str:
    """Compress a video using CRF-based encoding."""
    try:
        if not os.path.exists(input_path):
            return f"ERROR: input not found: {input_path}"
        args = f"-i {_quote(input_path)} -c:v {video_codec} -preset {preset} -crf {crf} -c:a aac -b:a {audio_bitrate_k}k {_quote(output_path)}"
        return run_ffmpeg(args)
    except Exception as e:
        return f"ERROR: {e}"
